import React, { useEffect, useState } from 'react';
import FormControl from '@material-ui/core/FormControl';
import InputLabel from '@material-ui/core/InputLabel';
import Select from '@material-ui/core/Select';
import MenuItem from '@material-ui/core/MenuItem';

function SelectCategory({
  selectedCategory,
  handleSelectChange,
  menuData,
  existingCategories,
}) {
  const [selectedMainCategory, setSelectedMainCategory] = useState('');
  const [selectedSubCategories, setSelectedSubCategories] = useState([]);

  useEffect(() => {
    if (existingCategories.length > 0) {
      const existingMainCategory = existingCategories[0].main;
      const existingSubCategories = existingCategories.map(cat => cat.sub);
      setSelectedMainCategory(existingMainCategory);
      setSelectedSubCategories(existingSubCategories);
    }
  }, [existingCategories]);

  const handleMainCategoryChange = (e) => {
    const mainCategory = e.target.value;
    setSelectedMainCategory(mainCategory);
    setSelectedSubCategories([]);
    handleSelectChange(e);
  };

  const handleSubCategoryChange = (e) => {
    setSelectedSubCategories(e.target.value);
    handleSelectChange(e);
  };

  return (
    <div>
      <FormControl variant="outlined">
        <InputLabel id="category">Category</InputLabel>
        <Select
          labelId="category"
          id="category"
          value={selectedCategory || selectedMainCategory}
          onChange={handleMainCategoryChange}
          label="Category"
        >
          {menuData.categories.map((category, index) => (
            <MenuItem key={index} value={category.mainMenu}>
              {category.mainMenu}
            </MenuItem>
          ))}
        </Select>
      </FormControl>
      {selectedMainCategory && (
        <FormControl variant="outlined">
          <InputLabel id="subCategory">Sub Category</InputLabel>
          <Select
            labelId="subCategory"
            id="subCategory"
            multiple
            value={selectedSubCategories}
            onChange={handleSubCategoryChange}
            label="Sub Category"
          >
            {menuData.subCategories[selectedMainCategory]?.map(
              (subCategory, index) => (
                <MenuItem key={index} value={subCategory}>
                  {subCategory}
                </MenuItem>
              )
            )}
          </Select>
        </FormControl>
      )}
    </div>
  );
}

export default SelectCategory;
